**Les filtres temporels sont critiques en SOC pour limiter la portée de l'analyse :**

```kql
// ─── Fenêtres temporelles ───
SecurityEvent
| where TimeGenerated > ago(1h)       // Dernière heure
| where TimeGenerated > ago(24h)      // Dernières 24h
| where TimeGenerated > ago(7d)       // 7 derniers jours

// Combiné avec d'autres filtres
SecurityEvent
| where TimeGenerated between(ago(48h) .. ago(24h))  // Avant-hier

// ─── Fonctions datetime ───
// startofday, startofweek, startofmonth
SecurityEvent
| where TimeGenerated >= startofday(now())

// ─── bin() : regrouper par intervalles ───
// Essentiel pour les graphiques temporels
SecurityEvent
| where TimeGenerated > ago(24h)
| where EventID == 4625
| summarize Echecs=count() by bin(TimeGenerated, 1h)
| render timechart

// ─── Formatage ───
SecurityEvent
| extend JourHeure = format_datetime(TimeGenerated, 'yyyy-MM-dd HH:mm')

// ─── Comparaison horodatage ───
// ago(duration) est la façon KQL de dire "il y a N"
// 1h = 1 heure, 30m = 30 minutes, 7d = 7 jours
```
